local m={}local U=game:GetService("UserInputService")local P=game:GetService("Players")local V=game:GetService("VirtualInputManager")local p=P.LocalPlayer local tF=workspace:WaitForChild("Thrown")local lF=workspace:WaitForChild("Live")local e=false local c local ch=p:WaitForChild("Charge")local g=false local function u()g=(ch.Value>320)end u()ch:GetPropertyChangedSignal("Value"):Connect(u)local function lc()for i=1,3 do V:SendMouseButtonEvent(0,0,0,true,game,0)task.wait(0.01)V:SendMouseButtonEvent(0,0,0,false,game,0)end end local function gk()V:SendKeyEvent(true,Enum.KeyCode.G,false,game)task.wait()V:SendKeyEvent(false,Enum.KeyCode.G,false,game)end local function gp(mo)return P:GetPlayerFromCharacter(mo)end local function tr(gb)if not gb then return end local mc=p.Character local tc tc=gb.Touched:Connect(function(h)if not e then return end local mo=h:FindFirstAncestorOfClass("Model")if not mo then return end if mo.Parent~=lF then return end if mo==mc then return end local tp=gp(mo)if tp and tp.Team==p.Team then return end lc()end)task.delay(2,function()if tc then tc:Disconnect()end end)end local function oi(i,gp)if gp or not e then return end if i.KeyCode==Enum.KeyCode.Three then local gb=tF:WaitForChild("GrabBall",1)if gb then tr(gb)end end if i.KeyCode==Enum.KeyCode.Two then if g then task.delay(0.03,function()if e and g then gk()end end)end end end function m:Enable()if e then return end e=true c=U.InputBegan:Connect(oi)end function m:Disable()e=false if c then c:Disconnect()c=nil end end function m.Start()m:Enable()end function m.Stop()m:Disable()end return m
